"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useParams } from "next/navigation";
import BackButton from "../../../../../components/BackButton";
import { fetchApi } from "../../../../../utils/api";

export default function editClassroomPage() {
  const { id } = useParams();
  const [formData, setFormData] = useState({
    id: "",
    name: "",
    description: "",
    enable_external_invite: false,
    status: "",
    cover_img: null as File | null,
    wallpaper_img: null as File | null,
  });
  const [existingCover, setExistingCover] = useState<string | null>(null);
  const [existingWallpaper, setExistingWallpaper] = useState<string | null>(null);
  const [removeCover, setRemoveCover] = useState(false);
  const [removeWallpaper, setRemoveWallpaper] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!id) return;

    const fetchClassroom = async () => {
      try {
        const result = await fetchApi(`/api/v1/classrooms/${id}`);
        const data = result.data || result;
        setFormData({
          id: data.id || "",
          name: data.name || "",
          description: data.description || "",
          enable_external_invite: !!data.is_external_invite_enable || !!data.enable_external_invite,
          status: data.status || "",
          cover_img: null,
          wallpaper_img: null,
        });
        setExistingCover(data.cover_img || null);
        setExistingWallpaper(data.wallpaper_img || null);
      } catch (error) {
        console.error("Gagal mengambil data kelas:", error);
        alert("Gagal memuat data kelas.");
      } finally {
        setLoading(false);
      }
    };

    fetchClassroom();
  }, [id]);

  if (loading) return <div style={{ color: "white" }}>Memuat data...</div>;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // 1. Buat instance FormData
    const payload = new FormData();

    // 2. Masukkan field-field ke dalam FormData
    payload.append("id", formData.id);
    payload.append("name", formData.name);
    payload.append("description", formData.description);
    payload.append(
      "is_external_invite_enable",
      String(formData.enable_external_invite),
    );
    payload.append("status", formData.status);

    // console.log("ID yang dikirim:", id);
    // console.log("URL lengkap:", `/api/v1/classrooms/${id}`);

    // 3. Masukkan file jika ada, atau tanda hapus
    if (formData.cover_img) {
      payload.append("cover_img", formData.cover_img);
    } else if (removeCover) {
      payload.append("delete_cover_img", "true");
    }

    if (formData.wallpaper_img) {
      payload.append("wallpaper_img", formData.wallpaper_img);
    } else if (removeWallpaper) {
      payload.append("delete_wallpaper_img", "true");
    }

    try {
      // 4. Kirim ke API menggunakan fetch
      await fetchApi(`/api/v1/classrooms/${id}`, {
        method: "PUT",
        body: payload,
      });

      alert("Update kelas berhasil!");
      window.location.href = "/admin/classrooms";
    } catch (error) {
      console.error("Error:", error);
      alert("Terjadi kesalahan sistem.");
    }
  };

  const handleDelete = async () => {
    if (
      !confirm(
        "Apakah Anda yakin ingin menghapus kelas ini? Tindakan ini tidak dapat dibatalkan.",
      )
    ) {
      return;
    }

    try {
      // Sesuaikan path jika endpoint delete kamu berbeda
      await fetchApi(`/api/v1/classrooms/${id}`, {
        method: "DELETE",
      });

      alert("Kelas berhasil dihapus!");
      window.location.href = "/admin/classrooms";
    } catch (error) {
      console.error("Error:", error);
      alert("Gagal menghapus kelas.");
    }
  };

  const renderImageUpload = (
    label: string,
    existingUrl: string | null,
    newFile: File | null,
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void,
    onRemove: () => void
  ) => {
    const previewUrl = newFile ? URL.createObjectURL(newFile) : existingUrl;

    return (
      <div>
        <label
          style={{
            display: "block",
            color: "#a0a5b5",
            marginBottom: "8px",
            fontWeight: "600",
          }}
        >
          {label}
        </label>
        <label
          style={{
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            width: "100%",
            height: "160px",
            borderRadius: "12px",
            border: "2px dashed rgba(255,255,255,0.2)",
            backgroundColor: "rgba(0,0,0,0.3)",
            cursor: "pointer",
            overflow: "hidden",
            position: "relative",
            transition: "all 0.2s",
          }}
          onMouseOver={(e) => (e.currentTarget.style.borderColor = "#ff477e")}
          onMouseOut={(e) => (e.currentTarget.style.borderColor = "rgba(255,255,255,0.2)")}
        >
          {previewUrl ? (
            <>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img src={previewUrl} alt={label} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              <div
                style={{
                  position: "absolute",
                  bottom: 0,
                  left: 0,
                  right: 0,
                  background: "linear-gradient(to top, rgba(0,0,0,0.8), transparent)",
                  color: "white",
                  textAlign: "center",
                  padding: "20px 8px 8px 8px",
                  fontSize: "0.85rem",
                  fontWeight: "500",
                }}
              >
                Ubah Gambar
              </div>
              <button
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  onRemove();
                }}
                style={{
                  position: "absolute",
                  top: "8px",
                  right: "8px",
                  backgroundColor: "rgba(0,0,0,0.6)",
                  backdropFilter: "blur(4px)",
                  border: "none",
                  borderRadius: "50%",
                  width: "32px",
                  height: "32px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  cursor: "pointer",
                  color: "#ef4444",
                  transition: "all 0.2s",
                  zIndex: 10,
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.backgroundColor = "#ef4444";
                  e.currentTarget.style.color = "white";
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.backgroundColor = "rgba(0,0,0,0.6)";
                  e.currentTarget.style.color = "#ef4444";
                }}
                title="Hapus Gambar"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M3 6h18"></path>
                  <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                </svg>
              </button>
            </>
          ) : (
            <div style={{ color: "#a0a5b5", textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center" }}>
              <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{ marginBottom: "12px", opacity: 0.7 }}>
                <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                <circle cx="8.5" cy="8.5" r="1.5"></circle>
                <polyline points="21 15 16 10 5 21"></polyline>
              </svg>
              <div style={{ fontSize: "0.9rem", fontWeight: "500" }}>Pilih Gambar</div>
              <div style={{ fontSize: "0.75rem", opacity: 0.6, marginTop: "4px" }}>PNG, JPG, WebP</div>
            </div>
          )}
          <input type="file" accept="image/*" onChange={onChange} style={{ display: "none" }} />
        </label>
      </div>
    );
  };

  return (
    <div className="animate-fade-in" style={{ maxWidth: "700px" }}>
      <div
        style={{
          marginBottom: "2rem",
          display: "flex",
          alignItems: "center",
          gap: "1rem",
        }}
      >
        <div style={{ flexShrink: 0 }}>
          <BackButton href="/admin/classrooms" />
        </div>
        <div>
          <h1 style={{ color: "white", fontSize: "1.8rem", margin: 0 }}>
            Edit Classroom
          </h1>
        </div>
      </div>

      <div
        style={{
          backgroundColor: "rgba(255,255,255,0.05)",
          backdropFilter: "blur(10px)",
          padding: "2rem",
          borderRadius: "16px",
          border: "1px solid rgba(255,255,255,0.1)",
        }}
      >
        <form
          onSubmit={handleSubmit}
          style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}
        >
          <div>
            <label
              style={{
                display: "block",
                color: "#a0a5b5",
                marginBottom: "8px",
                fontWeight: "600",
              }}
            >
              Nama Kelas
            </label>
            <input
              type="text"
              placeholder="Contoh: Kalkulus XII MIPA 1"
              value={formData.name}
              onChange={(e) =>
                setFormData({ ...formData, name: e.target.value })
              }
              required
              style={{
                width: "100%",
                padding: "12px 16px",
                borderRadius: "8px",
                backgroundColor: "rgba(0,0,0,0.3)",
                border: "1px solid rgba(255,255,255,0.2)",
                color: "white",
                outline: "none",
              }}
            />
          </div>

          <div>
            <label
              style={{
                display: "block",
                color: "#a0a5b5",
                marginBottom: "8px",
                fontWeight: "600",
              }}
            >
              Deskripsi Kelas
            </label>
            <textarea
              placeholder="Tuliskan deksripsi atau aturan kelas..."
              value={formData.description}
              onChange={(e) =>
                setFormData({ ...formData, description: e.target.value })
              }
              rows={4}
              style={{
                width: "100%",
                padding: "12px 16px",
                borderRadius: "8px",
                backgroundColor: "rgba(0,0,0,0.3)",
                border: "1px solid rgba(255,255,255,0.2)",
                color: "white",
                outline: "none",
                resize: "vertical",
              }}
            />
          </div>

          <div>
            <label
              style={{
                display: "block",
                color: "#a0a5b5",
                marginBottom: "8px",
                fontWeight: "600",
              }}
            >
              Enable External Invite
            </label>
            <select
              value={formData.enable_external_invite ? "yes" : "no"}
              onChange={(e) =>
                setFormData({
                  ...formData,
                  enable_external_invite: e.target.value === "yes",
                })
              }
              style={{
                width: "100%",
                padding: "12px 16px",
                borderRadius: "8px",
                backgroundColor: "rgba(0,0,0,0.3)",
                border: "1px solid rgba(255,255,255,0.2)",
                color: "white",
                outline: "none",
                cursor: "pointer",
              }}
            >
              <option value="yes">Yes</option>
              <option value="no">No</option>
            </select>
          </div>

          <div>
            <label
              style={{
                display: "block",
                color: "#a0a5b5",
                marginBottom: "8px",
                fontWeight: "600",
              }}
            >
              Status
            </label>
            <select
              value={formData.status} // Mengambil nilai string dari state
              onChange={(e) =>
                setFormData({ ...formData, status: e.target.value })
              }
              style={{
                width: "100%",
                padding: "12px 16px",
                borderRadius: "8px",
                backgroundColor: "rgba(0,0,0,0.3)",
                border: "1px solid rgba(255,255,255,0.2)",
                color: "white",
                outline: "none",
                cursor: "pointer",
              }}
            >
              <option value="" disabled>
                Pilih Status
              </option>
              <option value="ACTIVE">Active</option>
              <option value="ARCHIEVED">Archived</option>
              <option value="DRAFT">Draft</option>
            </select>
          </div>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "1rem",
            }}
          >
            {renderImageUpload(
              "Cover",
              existingCover,
              formData.cover_img,
              (e) => {
                setFormData({ ...formData, cover_img: e.target.files?.[0] || null });
                if (e.target.files?.[0]) setRemoveCover(false);
              },
              () => {
                setFormData({ ...formData, cover_img: null });
                setExistingCover(null);
                setRemoveCover(true);
              }
            )}
            
            {renderImageUpload(
              "Wallpaper",
              existingWallpaper,
              formData.wallpaper_img,
              (e) => {
                setFormData({ ...formData, wallpaper_img: e.target.files?.[0] || null });
                if (e.target.files?.[0]) setRemoveWallpaper(false);
              },
              () => {
                setFormData({ ...formData, wallpaper_img: null });
                setExistingWallpaper(null);
                setRemoveWallpaper(true);
              }
            )}
          </div>

          <div style={{
            display: "flex",
            justifyContent: "flex-end",
            alignItems: "center",
            gap: "1rem",
            marginTop: "2rem",
            paddingTop: "1.5rem",
            borderTop: "1px solid rgba(255,255,255,0.05)"
          }}>
            <button
              type="button"
              onClick={handleDelete}
              style={{
                padding: "10px 20px",
                backgroundColor: "rgba(239, 68, 68, 0.05)",
                color: "#ef4444",
                border: "1px solid rgba(239, 68, 68, 0.2)",
                borderRadius: "8px",
                fontWeight: "500",
                fontSize: "0.95rem",
                cursor: "pointer",
                transition: "all 0.2s",
              }}
              onMouseOver={(e) => {
                e.currentTarget.style.backgroundColor = "rgba(239, 68, 68, 0.15)";
                e.currentTarget.style.borderColor = "rgba(239, 68, 68, 0.4)";
              }}
              onMouseOut={(e) => {
                e.currentTarget.style.backgroundColor = "rgba(239, 68, 68, 0.05)";
                e.currentTarget.style.borderColor = "rgba(239, 68, 68, 0.2)";
              }}
            >
              Hapus Kelas
            </button>

            <button
              type="submit"
              style={{
                padding: "10px 24px",
                background: "linear-gradient(135deg, #ff477e, #ff6b9d)",
                color: "white",
                border: "none",
                borderRadius: "8px",
                fontWeight: "600",
                fontSize: "0.95rem",
                cursor: "pointer",
                transition: "all 0.2s",
                boxShadow: "0 4px 15px rgba(255, 71, 126, 0.3)",
              }}
              onMouseOver={(e) => {
                e.currentTarget.style.transform = "translateY(-1px)";
                e.currentTarget.style.boxShadow = "0 6px 20px rgba(255, 71, 126, 0.4)";
              }}
              onMouseOut={(e) => {
                e.currentTarget.style.transform = "translateY(0)";
                e.currentTarget.style.boxShadow = "0 4px 15px rgba(255, 71, 126, 0.3)";
              }}
            >
              Simpan Perubahan
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { fetchApi } from "../../../../utils/api";
import toast from "react-hot-toast";
import AdminPageHeader from "../../../../components/admin/AdminPageHeader";
import TopicCard from "../../../../components/admin/TopicCard";
import { useParams } from "next/navigation";

export default function AdminTopicsPage() {
  const { id } = useParams();
  const [topics, setTopics] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setIsLoading(true);

    // 1. Ambil SEMUA topik (karena endpoint ini yang berhasil)
    fetchApi("/api/v1/topics")
      .then((res) => {
        // 2. Filter data berdasarkan classroom_id yang ada di URL (id)
        const allTopics = res.data || [];
        const filteredTopics = allTopics.filter(
          (topic: any) => topic.classroom_id === id,
        );

        setTopics(filteredTopics);
      })
      .catch((err) => {
        toast.error("Gagal mengambil daftar topik: " + err.message);
      })
      .finally(() => {
        setIsLoading(false);
      });
  }, [id]); // Tambahkan [id] agar data ter-refresh jika pindah kelas

  const handleDelete = async (id: string, name: string) => {
    if (
      window.confirm(
        `Apakah Anda yakin ingin menghapus topik "${name}"? Tindakan ini tidak dapat dibatalkan.`,
      )
    ) {
      try {
        await fetchApi(`/api/v1/topics/${id}`, { method: "DELETE" });
        toast.success(`Topik "${name}" berhasil dihapus.`);
        setTopics(topics.filter((t) => t.id !== id));
      } catch (err: any) {
        toast.error("Gagal menghapus topik: " + err.message);
      }
    }
  };

  return (
    <div className="animate-fade-in">
      <div
        className="admin-page-header"
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "2rem",
          flexWrap: "wrap",
          gap: "1rem",
        }}
      >
        <div>
          <h1
            style={{
              color: "white",
              fontSize: "2rem",
              marginBottom: "0.5rem",
              fontWeight: "700",
            }}
          >
            Manajemen Classroom
          </h1>
          <p style={{ color: "#a0a5b5", fontSize: "1rem" }}>
            Kelola ruang kelas, lihat daftar murid, dan peringkat kelas.
          </p>
        </div>

        <Link
          href={`/admin/classrooms/${id}/topics/create`} // Gunakan backtick dan path yang benar
          style={{ textDecoration: "none" }}
        >
          <button
            style={{
              padding: "12px 24px",
              backgroundColor: "#ff477e",
              color: "white",
              border: "none",
              borderRadius: "8px",
              fontWeight: "600",
              cursor: "pointer",
            }}
          >
            Buat Topik
          </button>
        </Link>
      </div>

      {isLoading ? (
        <div style={{ textAlign: "center", padding: "3rem", color: "#a0a5b5" }}>
          Memuat daftar topik...
        </div>
      ) : topics.length === 0 ? (
        <div
          style={{
            textAlign: "center",
            padding: "3rem",
            color: "#a0a5b5",
            border: "1px dashed rgba(255,255,255,0.2)",
            borderRadius: "12px",
          }}
        >
          Belum ada topik yang ditambahkan. Silakan klik "Tambah Topik Soal".
        </div>
      ) : (
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
            gap: "1.5rem",
          }}
        >
          {topics.map((topic) => (
            <TopicCard key={topic.id} topic={topic} onDelete={handleDelete} />
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";

export default function Page() {
  return (
    <div>
      <h1>Topics</h1>
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import BackButton from "../../../../../../components/BackButton";
import { fetchApi } from "../../../../../../utils/api";
import { useParams } from "next/navigation";

export default function CreateTopicPage() {
  const params = useParams();
  const classroomId = params.id as string;
  const [isLoading, setIsLoading] = useState(false);

  const [formData, setFormData] = useState({
    name: "",
    description: "",
    female_normal_dialog: "",
    male_normal_dialog: "",
    female_dating_dialog: "",
    male_dating_dialog: "",
    status: "",
    level_settings: {
      Easy: { plus: 10, minus: 0 },
      Medium: { plus: 20, minus: -5 },
      Hard: { plus: 30, minus: -10 },
    },
    max_attempts: 0,
    female_normal_img: null as File | null,
    male_normal_img: null as File | null,
    female_dating_img: null as File | null,
    male_dating_img: null as File | null,
  });

  const levelSettingsArray = Object.entries(formData.level_settings).map(
    ([level, value]) => ({
      level: level.toLowerCase(),
      true_score: value.plus,
      false_score: value.minus,
    }),
  );

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // 1. Buat instance FormData
    const payload = new FormData();

    // 2. Masukkan field-field ke dalam FormData
    payload.append("classroom_id", classroomId);
    payload.append("name", formData.name);
    payload.append("description", formData.description);
    payload.append("female_normal_dialog", formData.female_normal_dialog);
    payload.append("male_normal_dialog", formData.male_normal_dialog);
    payload.append("female_dating_dialog", formData.female_dating_dialog);
    payload.append("male_dating_dialog", formData.male_dating_dialog);
    payload.append("status", formData.status);
    payload.append("level_settings", JSON.stringify(levelSettingsArray));
    payload.append("max_attempts", String(formData.max_attempts));

    // 3. Masukkan file jika ada
    if (formData.female_normal_img) {
      payload.append("female_normal_img", formData.female_normal_img);
    }

    if (formData.male_normal_img) {
      payload.append("male_normal_img", formData.male_normal_img);
    }

    if (formData.female_dating_img) {
      payload.append("female_dating_img", formData.female_dating_img);
    }

    if (formData.male_dating_img) {
      payload.append("male_dating_img", formData.male_dating_img);
    }

    try {
      // 4. Kirim ke API menggunakan fetch
      await fetchApi("/api/v1/topics", {
        method: "POST",
        body: payload,
        // Penting: Jangan set Content-Type secara manual saat menggunakan FormData
        // Browser akan otomatis menambahkan 'multipart/form-data' dengan boundary-nya
      });

      alert("Simpan topil berhasil!");
      window.location.href = "/admin/classrooms";
    } catch (error) {
      console.error("Error:", error);
      alert("Terjadi kesalahan sistem.");
    }
  };

  const fileInputStyle: React.CSSProperties = {
    width: "100%",
    padding: "10px",
    borderRadius: "8px",
    backgroundColor: "rgba(0,0,0,0.3)",
    border: "1px solid rgba(255,255,255,0.2)",
    color: "#a0a5b5",
    cursor: "pointer",
  };

  const inputStyle = {
    width: "100%",
    padding: "10px 14px",
    borderRadius: "8px",
    backgroundColor: "rgba(0,0,0,0.3)",
    border: "1px solid rgba(255,255,255,0.2)",
    color: "white",
    outline: "none",
    fontSize: "0.95rem",
  };

  const sectionStyle = {
    backgroundColor: "rgba(255,255,255,0.03)",
    border: "1px solid rgba(255,255,255,0.1)",
    borderRadius: "12px",
    padding: "1.5rem",
    display: "flex",
    flexDirection: "column" as const,
    gap: "1rem",
  };

  const handleLevelChange = (
    level: "Easy" | "Medium" | "Hard",
    field: "plus" | "minus",
    val: string,
  ) => {
    setFormData({
      ...formData,
      level_settings: {
        ...formData.level_settings,
        [level]: {
          ...formData.level_settings[level],
          [field]: parseInt(val) || 0,
