                  enable_external_invite: e.target.value === "yes",
                })
              }
              style={{
                width: "100%",
                padding: "12px 16px",
                borderRadius: "8px",
                backgroundColor: "rgba(0,0,0,0.3)",
                border: "1px solid rgba(255,255,255,0.2)",
                color: "white",
                outline: "none",
                cursor: "pointer",
              }}
            >
              <option value="yes">Yes</option>
              <option value="no">No</option>
            </select>
          </div>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "1rem",
            }}
          >
            <div>
              <label
                style={{
                  display: "block",
                  color: "#a0a5b5",
                  marginBottom: "8px",
                  fontWeight: "600",
                }}
              >
                Cover
              </label>
              <input
                type="file"
                accept="image/*"
                onChange={(e) =>
                  setFormData({
                    ...formData,
                    cover_img: e.target.files?.[0] || null,
                  })
                }
                style={fileInputStyle}
              />
            </div>
            <div>
              <label
                style={{
                  display: "block",
                  color: "#a0a5b5",
                  marginBottom: "8px",
                  fontWeight: "600",
                }}
              >
                Wallpaper
              </label>
              <input
                type="file"
                accept="image/*"
                onChange={(e) =>
                  setFormData({
                    ...formData,
                    wallpaper_img: e.target.files?.[0] || null,
                  })
                }
                style={fileInputStyle}
              />
            </div>
          </div>

          <button
            type="submit"
            style={{
              marginTop: "1rem",
              padding: "14px",
              backgroundColor: "#22c55e",
              color: "white",
              border: "none",
              borderRadius: "8px",
              fontWeight: "600",
              fontSize: "1.1rem",
              cursor: "pointer",
              transition: "all 0.2s",
              boxShadow: "0 4px 15px rgba(34, 197, 94, 0.3)",
            }}
            onMouseOver={(e) =>
              (e.currentTarget.style.backgroundColor = "#16a34a")
            }
            onMouseOut={(e) =>
              (e.currentTarget.style.backgroundColor = "#22c55e")
            }
          >
            Simpan Classroom
          </button>
        </form>
      </div>
    </div>
  );
}

