"use client";

import { useState, useEffect } from 'react';
import { fetchApi } from '../../../utils/api';

export default function AdminLeaderboardPage() {
  const [classrooms, setClassrooms] = useState<any[]>([]);
  const [filterClass, setFilterClass] = useState('ALL');
  const [topicsList, setTopicsList] = useState<any[]>([]);
  const [filterTopic, setFilterTopic] = useState('ALL');
  const [currentPage, setCurrentPage] = useState(1);
  const [leaderboard, setLeaderboard] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedRows, setExpandedRows] = useState<Set<string>>(new Set());
  const itemsPerPage = 5;

  useEffect(() => {
    const fetchClassrooms = async () => {
      try {
        const res = await fetchApi('/api/v1/classrooms');
        setClassrooms(res.data || res || []);
      } catch (err) {
        console.error("Gagal memuat kelas", err);
      }
    };
    fetchClassrooms();
  }, []);

  useEffect(() => {
    const fetchTopics = async () => {
      if (filterClass !== 'ALL') {
        try {
          const res = await fetchApi(`/api/v1/topics?classroomId=${filterClass}`);
          setTopicsList(res.data || []);
        } catch (err) {
          console.error("Gagal memuat topik untuk filter", err);
        }
      } else {
        setTopicsList([]);
      }
      setFilterTopic('ALL');
    };
    fetchTopics();
  }, [filterClass]);

  useEffect(() => {
    const fetchLeaderboard = async () => {
      setLoading(true);
      try {
        const userScores = new Map<string, any>();
        const classesToFetch = filterClass === 'ALL' ? classrooms : [{ id: filterClass }];

        for (const cls of classesToFetch) {
          if (!cls || !cls.id) continue;
          try {
            // Fetch topics for this classroom
            const topicsRes = await fetchApi(`/api/v1/topics?classroomId=${cls.id}`);
            const rawTopics = topicsRes.data || topicsRes;
            let topics = Array.isArray(rawTopics) ? rawTopics : [];

            // Filter by topic if a specific topic is selected
            if (filterTopic !== 'ALL') {
              topics = topics.filter((t: any) => t.id === filterTopic);
            }

            for (const topic of topics) {
              try {
                // Fetch leaderboard for this classroom & topic
                const lbRes = await fetchApi(`/api/v1/leaderboard?classroomId=${cls.id}&topicId=${topic.id}`);
                const rawData = lbRes.data || lbRes;
                const data = Array.isArray(rawData) ? rawData : [];

                for (const player of data) {
                  const uid = player.user_id;
                  if (!userScores.has(uid)) {
                    userScores.set(uid, {
                      ...player,
                      topicScores: [{ topicId: topic.id, topicName: topic.name, score: player.score || 0 }]
                    });
                  } else {
                    const existing = userScores.get(uid);
                    existing.score = (existing.score || 0) + (player.score || 0);
                    existing.topicScores.push({ topicId: topic.id, topicName: topic.name, score: player.score || 0 });
                  }
                }
              } catch (e) {
                console.error(`Gagal memuat leaderboard untuk topic ${topic.id}`, e);
              }
            }
          } catch (e) {
            console.error(`Gagal memuat topics untuk kelas ${cls.id}`, e);
          }
        }

        // Convert to array and sort by score descending
        const aggregated = Array.from(userScores.values());
        setLeaderboard(aggregated.sort((a, b) => (b.score || 0) - (a.score || 0)));
      } catch (err) {
        console.error("Gagal memuat leaderboard", err);
      } finally {
        setLoading(false);
      }
    };

    if (classrooms.length > 0 || filterClass !== 'ALL') {
      fetchLeaderboard();
    } else {
      setLoading(false);
    }
  }, [filterClass, filterTopic, classrooms]);

  const totalPages = Math.max(1, Math.ceil(leaderboard.length / itemsPerPage));

  const currentLeaderboard = leaderboard.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const getDisplayName = (player: any) => {
    if (player.first_name) {
      return `${player.first_name} ${player.last_name || ''}`.trim();
    }
    return player.username || player.name || 'Peserta';
  };

  const toggleRow = (uid: string) => {
    setExpandedRows(prev => {
      const newSet = new Set(prev);
      if (newSet.has(uid)) newSet.delete(uid);
      else newSet.add(uid);
      return newSet;
    });
  };

  return (
    <div className="animate-fade-in">
      <div className="admin-page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <h1 style={{ color: 'white', fontSize: '2rem', marginBottom: '0.5rem', fontWeight: '700' }}>
            Leaderboard (Analisis Detail)
          </h1>
          <p style={{ color: '#a0a5b5', fontSize: '1rem', margin: 0 }}>
            Pantau statistik rinci tiap percobaan murid, skor, dan akurasi jawaban.
          </p>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <label style={{ color: '#a0a5b5', fontSize: '0.85rem' }}>Filter Kelas:</label>
            <select
              value={filterClass}
              onChange={(e) => {
                setFilterClass(e.target.value);
                setCurrentPage(1); // Reset page on filter change
              }}
              style={{
                padding: '8px 16px', borderRadius: '8px', backgroundColor: 'rgba(0,0,0,0.3)', color: 'white',
                border: '1px solid rgba(255,255,255,0.2)', outline: 'none', cursor: 'pointer'
              }}
            >
              <option value="ALL">Semua Kelas</option>
              {classrooms.map(cls => (
                <option key={cls.id} value={cls.id}>{cls.name}</option>
              ))}
            </select>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <label style={{ color: '#a0a5b5', fontSize: '0.85rem' }}>Filter Materi:</label>
            <select
              value={filterTopic}
              onChange={(e) => {
                setFilterTopic(e.target.value);
                setCurrentPage(1);
              }}
              disabled={filterClass === 'ALL'}
              style={{
                padding: '8px 16px', borderRadius: '8px', backgroundColor: filterClass === 'ALL' ? 'rgba(0,0,0,0.1)' : 'rgba(0,0,0,0.3)', color: filterClass === 'ALL' ? 'rgba(255,255,255,0.3)' : 'white',
                border: '1px solid rgba(255,255,255,0.2)', outline: 'none', cursor: filterClass === 'ALL' ? 'not-allowed' : 'pointer'
              }}
            >
              <option value="ALL">Semua Materi</option>
              {topicsList.map(topic => (
                <option key={topic.id} value={topic.id}>{topic.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div style={{
        backgroundColor: 'rgba(255,255,255,0.05)',
        backdropFilter: 'blur(10px)',
        borderRadius: '16px',
        border: '1px solid rgba(255,255,255,0.1)',
        overflowX: 'auto'
      }}>
        <div style={{ minWidth: '900px' }}>
          {/* Table Header */}
          <div style={{
            display: 'grid', gridTemplateColumns: '50px 3fr 1.5fr 50px',
            padding: '16px 24px',
            backgroundColor: 'rgba(255,255,255,0.05)',
            borderBottom: '1px solid rgba(255,255,255,0.1)',
            alignItems: 'center'
          }}>
            {['Rank', 'Peserta', 'Total Poin', ''].map(h => (
              <span key={h} style={{ color: '#a0a5b5', fontSize: '0.85rem', fontWeight: '700', textTransform: 'uppercase' }}>{h}</span>
            ))}
          </div>

          {/* Table Rows */}
          {loading ? (
            <div style={{ padding: '2rem', color: 'white', textAlign: 'center' }}>Memuat leaderboard...</div>
          ) : currentLeaderboard.length === 0 ? (
            <div style={{ padding: '2rem', color: '#a0a5b5', textAlign: 'center' }}>Belum ada data peringkat.</div>
          ) : (
            currentLeaderboard.map((player, idx) => {
              const actualRank = ((currentPage - 1) * itemsPerPage) + idx;
              const displayName = getDisplayName(player);
              const avatarUrl = player.profile_picture_url || '/char-mc.png';
              const uid = player.user_id || idx.toString();
              const isExpanded = expandedRows.has(uid);
              const hasTopics = player.topicScores && player.topicScores.length > 0;

              return (
                <div key={uid} style={{ display: 'flex', flexDirection: 'column' }}>
                  <div style={{
                    display: 'grid', gridTemplateColumns: '50px 3fr 1.5fr 50px',
                    padding: '16px 24px',
                    borderBottom: (idx < currentLeaderboard.length - 1 && !isExpanded) ? '1px solid rgba(255,255,255,0.05)' : 'none',
                    alignItems: 'center',
                    transition: 'background-color 0.2s',
                    backgroundColor: isExpanded ? 'rgba(255,255,255,0.02)' : 'transparent',
                    cursor: filterTopic === 'ALL' && hasTopics ? 'pointer' : 'default'
                  }}
                    onClick={() => { if (filterTopic === 'ALL' && hasTopics) toggleRow(uid); }}
                    onMouseOver={(e) => e.currentTarget.style.backgroundColor = 'rgba(255,255,255,0.05)'}
                    onMouseOut={(e) => e.currentTarget.style.backgroundColor = isExpanded ? 'rgba(255,255,255,0.02)' : 'transparent'}>

                    <span style={{
                      color: actualRank === 0 ? '#FFD700' : actualRank === 1 ? '#C0C0C0' : actualRank === 2 ? '#CD7F32' : '#a0a5b5',
                      fontWeight: '900', fontSize: '1.2rem'
                    }}>
                      #{actualRank + 1}
                    </span>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                      <div style={{ width: '32px', height: '32px', borderRadius: '50%', backgroundColor: '#64748b', backgroundImage: `url("${avatarUrl}")`, backgroundSize: 'cover', backgroundPosition: 'top' }}></div>
                      <div>
                        <p style={{ color: 'white', fontWeight: '600', fontSize: '0.95rem', margin: '0 0 2px 0' }}>{displayName}</p>
                        <p style={{ color: '#a0a5b5', fontSize: '0.8rem', margin: 0 }}>{player.email || '-'}</p>
                      </div>
                    </div>

                    <span style={{
                      color: (player.score || 0) < 0 ? '#ef4444' : '#22c55e',
                      fontWeight: '800', fontSize: '1.2rem',
                      textShadow: (player.score || 0) > 0 ? '0 0 10px rgba(34, 197, 94, 0.3)' : 'none'
                    }}>
                      {(player.score || 0).toLocaleString()}
                    </span>

                    {filterTopic === 'ALL' && hasTopics && (
                      <span style={{ color: '#a0a5b5', textAlign: 'center', transform: isExpanded ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }}>
                        ▼
                      </span>
                    )}
                  </div>

                  {/* Expanded Breakdown Rows */}
                  {isExpanded && filterTopic === 'ALL' && hasTopics && (
                    <div style={{
                      backgroundColor: 'rgba(0,0,0,0.2)',
                      padding: '1rem 2rem 1rem 4rem',
                      borderBottom: idx < currentLeaderboard.length - 1 ? '1px solid rgba(255,255,255,0.05)' : 'none'
                    }}>
                      <p style={{ color: '#a0a5b5', fontSize: '0.85rem', fontWeight: '600', marginBottom: '0.5rem', textTransform: 'uppercase' }}>Poin per Materi :</p>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {player.topicScores.map((ts: any, tidx: number) => (
                          <div key={tidx} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 16px', backgroundColor: 'rgba(255,255,255,0.03)', borderRadius: '8px' }}>
                            <span style={{ color: 'white', fontSize: '0.9rem' }}>{ts.topicName || `Topik ${tidx + 1}`}</span>
                            <span style={{ color: ts.score < 0 ? '#ef4444' : '#22c55e', fontWeight: 'bold' }}>{ts.score > 0 ? `+${ts.score}` : ts.score}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
          <p style={{ color: '#a0a5b5', fontSize: '0.9rem', margin: 0 }}>
            Menampilkan <strong style={{ color: 'white' }}>{leaderboard.length > 0 ? ((currentPage - 1) * itemsPerPage) + 1 : 0} - {Math.min(currentPage * itemsPerPage, leaderboard.length)}</strong> dari total <strong style={{ color: 'white' }}>{leaderboard.length}</strong> riwayat
          </p>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button
              disabled={currentPage === 1}
              onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
              style={{
                padding: '8px 16px',
                backgroundColor: currentPage === 1 ? 'rgba(255,255,255,0.05)' : 'rgba(255,255,255,0.1)',
                color: currentPage === 1 ? 'rgba(255,255,255,0.3)' : 'white',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '8px',
                fontWeight: '600',
                cursor: currentPage === 1 ? 'not-allowed' : 'pointer',
                transition: 'all 0.2s'
              }}
            >
              Sebelumnya
            </button>

            <div style={{ display: 'flex', alignItems: 'center', padding: '0 8px', color: 'white', fontWeight: 'bold' }}>
              {currentPage} / {totalPages}
            </div>

            <button
              disabled={currentPage === totalPages}
              onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
              style={{
                padding: '8px 16px',
                backgroundColor: currentPage === totalPages ? 'rgba(255,255,255,0.05)' : 'rgba(255, 71, 126, 0.8)',
                color: currentPage === totalPages ? 'rgba(255,255,255,0.3)' : 'white',
                border: currentPage === totalPages ? '1px solid rgba(255,255,255,0.1)' : '1px solid rgba(255, 71, 126, 0.5)',
                borderRadius: '8px',
                fontWeight: '600',
                cursor: currentPage === totalPages ? 'not-allowed' : 'pointer',
                transition: 'all 0.2s',
                boxShadow: currentPage === totalPages ? 'none' : '0 4px 10px rgba(255, 71, 126, 0.3)'
              }}
            >
              Selanjutnya
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from 'react';
import UserRow from '../../../components/admin/UserRow';
import { fetchApi } from '../../../utils/api';

export default function AdminPeoplePage() {
  const [currentPage, setCurrentPage] = useState(1);
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const itemsPerPage = 5;
  const totalPages = Math.ceil(users.length / itemsPerPage);

  const currentUsers = users.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  useEffect(() => {
    const fetchAllMembers = async () => {
      try {
        setLoading(true);
        // 1. Ambil semua kelas
        const classRes = await fetchApi('/api/v1/classrooms');
        const classrooms = classRes.data || classRes || [];

        // 2. Kumpulkan semua members dari setiap kelas
        const allMembersMap = new Map();

        for (const cls of classrooms) {
          try {
            const memberRes = await fetchApi(`/api/v1/classrooms/${cls.id}/members`);
            const members = memberRes.data || memberRes || [];
            members.forEach((m: any) => {
              // Gunakan user_id atau id sebagai key untuk menghindari duplikat
              const id = m.user_id || m.id;
              if (!allMembersMap.has(id)) {
                allMembersMap.set(id, m);
              }
            });
          } catch (e) {
            console.error(`Gagal mengambil member untuk kelas ${cls.id}`);
          }
        }

        // 3. Konversi Map ke Array
        setUsers(Array.from(allMembersMap.values()));
      } catch (err) {
        console.error("Gagal memuat classrooms/members", err);
      } finally {
        setLoading(false);
      }
    };

    fetchAllMembers();
  }, []);

  return (
    <div className="animate-fade-in">
      {loading ? (
        <div style={{ color: 'white', fontSize: '1.2rem', padding: '2rem' }}>
          Memuat data pengguna...
        </div>
      ) : (
      <>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h1 style={{ color: 'white', fontSize: '2rem', marginBottom: '0.5rem', fontWeight: '700' }}>
            Pantauan Pengguna (People)
          </h1>
          <p style={{ color: '#a0a5b5', fontSize: '1rem' }}>
            Daftar semua siswa yang terdaftar di aplikasi.
          </p>
        </div>
      </div>

      <div style={{
        backgroundColor: 'rgba(255,255,255,0.05)',
        backdropFilter: 'blur(10px)',
        borderRadius: '16px',
        border: '1px solid rgba(255,255,255,0.1)',
        overflowX: 'auto'
      }}>
        <div style={{ minWidth: '800px' }}>
        {/* Table Header */}
        <div style={{
          display: 'grid', gridTemplateColumns: '2fr 3fr 1fr 1fr 1fr',
          padding: '16px 24px',
          backgroundColor: 'rgba(255,255,255,0.05)',
          borderBottom: '1px solid rgba(255,255,255,0.1)'
        }}>
          {['Nama Lengkap', 'Email', 'Gender', 'Role', 'Aksi'].map(h => (
            <span key={h} style={{ color: '#ffffffff', fontSize: '0.85rem', fontWeight: '700', textTransform: 'uppercase' }}>{h}</span>
          ))}
        </div>

        {/* Table Rows */}
        {currentUsers.map((user, idx) => (
          <UserRow key={user.id || user.user_id || `user-${idx}`} user={user} isLastRow={idx === currentUsers.length - 1} />
        ))}
        </div>
      </div>

      {/* Pagination Controls */}
      {totalPages > 1 && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
          <p style={{ color: '#a0a5b5', fontSize: '0.9rem', margin: 0 }}>
            Menampilkan <strong style={{ color: 'white' }}>{((currentPage - 1) * itemsPerPage) + 1} - {Math.min(currentPage * itemsPerPage, users.length)}</strong> dari total <strong style={{ color: 'white' }}>{users.length}</strong> pengguna
          </p>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button 
              disabled={currentPage === 1}
              onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
              style={{
                padding: '8px 16px',
                backgroundColor: currentPage === 1 ? 'rgba(255,255,255,0.05)' : 'rgba(255,255,255,0.1)',
                color: currentPage === 1 ? 'rgba(255,255,255,0.3)' : 'white',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '8px',
                fontWeight: '600',
                cursor: currentPage === 1 ? 'not-allowed' : 'pointer',
                transition: 'all 0.2s'
              }}
            >
              Sebelumnya
            </button>
            
            <div style={{ display: 'flex', alignItems: 'center', padding: '0 8px', color: 'white', fontWeight: 'bold' }}>
              {currentPage} / {totalPages}
            </div>

            <button 
              disabled={currentPage === totalPages}
              onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
              style={{
                padding: '8px 16px',
                backgroundColor: currentPage === totalPages ? 'rgba(255,255,255,0.05)' : 'rgba(255, 71, 126, 0.8)',
                color: currentPage === totalPages ? 'rgba(255,255,255,0.3)' : 'white',
                border: currentPage === totalPages ? '1px solid rgba(255,255,255,0.1)' : '1px solid rgba(255, 71, 126, 0.5)',
                borderRadius: '8px',
                fontWeight: '600',
                cursor: currentPage === totalPages ? 'not-allowed' : 'pointer',
                transition: 'all 0.2s',
                boxShadow: currentPage === totalPages ? 'none' : '0 4px 10px rgba(255, 71, 126, 0.3)'
              }}
            >
              Selanjutnya
            </button>
          </div>
        </div>
      )}
      </>
      )}
    </div>
  );
}

"use client";

import { useState, use, useEffect } from "react";
import Link from "next/link";
import { fetchApi } from "../../../../../utils/api";
import BackButton from "../../../../../components/BackButton";
import toast from "react-hot-toast";
import { useParams } from "next/navigation";

interface QuestionDraft {
  id?: string;
  content: string;
  level: "Easy" | "Medium" | "Hard";
  timeLimit: number;
  options: string[];
  correct_index: number;
}

export default function EditQuestionsPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const resolvedParams = use(params);
  const [questions, setQuestions] = useState<QuestionDraft[]>([]);
  const [activeTab, setActiveTab] = useState(0);
  const [topicName, setTopicName] = useState<string>("");
  const [isLoading, setIsLoading] = useState(true);

  const fetchAllQuestions = async (topicId: string) => {
    let page = 1;
    const allQuestions = [];

    while (true) {
      const res = await fetchApi(
        `/api/v1/questions?topicId=${topicId}&page=${page}`,
      );

      const data = res.data || [];

      if (data.length === 0) break;

      allQuestions.push(...data);
      page++;
    }

    return allQuestions;
  };

  useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true);
        // Fetch Topic Name
        const topicRes = await fetchApi(`/api/v1/topics/${resolvedParams.id}`);
        if (topicRes.data) {
          setTopicName(topicRes.data.name || "");
        }

        // Fetch existing questions
        // const qRes = await fetchApi(`/api/v1/questions?topicId=${resolvedParams.id}`);
        // const existingQuestions = qRes.data || [];
        const existingQuestions = await fetchAllQuestions(resolvedParams.id);

        const mappedQuestions: QuestionDraft[] = existingQuestions.map(
          (q: any) => {
            let correctIdx = 0;
            const opts = q.options?.map((opt: any, idx: number) => {
              if (opt.is_correct) correctIdx = idx;
              return opt.content;
            }) || ["", "", "", ""];

            // Ensure we have 4 options
            while (opts.length < 4) opts.push("");

            return {
              id: q.id,
              content: q.content,
              level: (q.level
                ? q.level.charAt(0).toUpperCase() +
                  q.level.slice(1).toLowerCase()
                : "Easy") as "Easy" | "Medium" | "Hard",
              timeLimit: q.time_limit || 30,
              options: opts,
              correct_index: correctIdx,
            };
          },
        );

        if (mappedQuestions.length > 0) {
          setQuestions(mappedQuestions);
        } else {
          setQuestions([
            {
              content: "",
              level: "Easy",
              timeLimit: 30,
              options: ["", "", "", ""],
              correct_index: 0,
            },
          ]);
        }
      } catch (err: any) {
        toast.error("Gagal memuat data: " + err.message);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [resolvedParams.id]);

  const handleAddQuestion = () => {
    setQuestions([
      ...questions,
      {
        content: "",
        level: "Easy",
        timeLimit: 30,
        options: ["", "", "", ""],
        correct_index: 0,
      },
    ]);
    setActiveTab(questions.length);
  };

  const handleUpdate = (field: keyof QuestionDraft, value: any) => {
    const updated = [...questions];
    updated[activeTab] = { ...updated[activeTab], [field]: value };
    setQuestions(updated);
  };

  const handleOptionChange = (idx: number, value: string) => {
    const updated = [...questions];
    updated[activeTab].options[idx] = value;
    setQuestions(updated);
  };

  const handleDelete = async (idx: number) => {
    const q = questions[idx];

    try {
      if (q.id) {
        await fetchApi(`/api/v1/questions/${q.id}`, {
          method: "DELETE",
        });
      }

      const updated = questions.filter((_, i) => i !== idx);
      setQuestions(updated);
      setActiveTab(Math.max(0, idx - 1));

      toast.success("Soal berhasil dihapus");
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleSaveAll = async () => {
    setIsLoading(true);

    try {
      for (const q of questions) {
        const payload = {
          content: q.content,
          level: q.level.toLowerCase(),
          timeLimit: q.timeLimit,
          topicId: resolvedParams.id,
          options: q.options.map((opt, idx) => ({
            content: opt,
            isCorrect: idx === q.correct_index,
          })),
        };

        if (q.id) {
          // UPDATE
          await fetchApi(`/api/v1/questions/${q.id}`, {
            method: "PUT",
            body: JSON.stringify(payload),
          });
        } else {
          // CREATE
          await fetchApi("/api/v1/questions/batch", {
            method: "POST",
            body: JSON.stringify({
              topicId: resolvedParams.id,
              level: q.level.toLowerCase(),
              questions: [
                {
                  content: q.content,
                  timeLimit: q.timeLimit,
                  options: q.options.map((opt, idx) => ({
                    content: opt,
                    isCorrect: idx === q.correct_index,
                  })),
                },
              ],
            }),
          });
        }
      }

      toast.success("Berhasil menyimpan!");

      // reload supaya id soal baru ikut terisi
      const refreshed = await fetchAllQuestions(resolvedParams.id);

      const mapped = refreshed.map((q: any) => {
        let correctIdx = 0;

        const opts = q.options?.map((o: any, idx: number) => {
          if (o.is_correct) correctIdx = idx;
          return o.content;
        }) ?? ["", "", "", ""];

        while (opts.length < 4) opts.push("");

        return {
          id: q.id,
          content: q.content,
          level: (q.level.charAt(0).toUpperCase() +
            q.level.slice(1).toLowerCase()) as "Easy" | "Medium" | "Hard",
          timeLimit: q.time_limit,
          options: opts,
          correct_index: correctIdx,
        };
      });

      setQuestions(mapped);
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const activeQ = questions[activeTab];
  const characterName = topicName || resolvedParams.id.replace(/-/g, " ");

  if (isLoading && questions.length === 0) {
    return <div style={{ color: "white", padding: "2rem" }}>Memuat...</div>;
  }

  return (
    <div
      className="animate-fade-in"
      style={{ display: "flex", gap: "2rem", height: "100%" }}
    >
      {/* Sidebar untuk Daftar Soal */}
      <div
        style={{
          width: "320px",
          backgroundColor: "rgba(255,255,255,0.05)",
          backdropFilter: "blur(10px)",
          border: "1px solid rgba(255,255,255,0.1)",
          borderRadius: "16px",
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            padding: "1.5rem",
            borderBottom: "1px solid rgba(255,255,255,0.1)",
          }}
        >
          <BackButton
            href="/admin/classrooms/"
            style={{ marginBottom: "1rem" }}
          />
          <h2 style={{ color: "white", fontSize: "1.2rem", margin: 0 }}>
            Kelola Soal
          </h2>
          <div
            style={{
              display: "inline-block",
              marginTop: "10px",
              padding: "4px 12px",
              backgroundColor: "rgba(240, 148, 77, 0.2)",
              border: "1px solid rgba(240, 148, 77, 0.4)",
              borderRadius: "20px",
              color: "#f0944d",
              fontSize: "0.85rem",
              fontWeight: "bold",
              textTransform: "capitalize",
              maxWidth: "100%",
              overflow: "hidden",
              textOverflow: "ellipsis",
              whiteSpace: "nowrap",
            }}
          >
            📚 Topik: {characterName}
          </div>
        </div>

        <div style={{ flex: 1, overflowY: "auto", padding: "1rem" }}>
          {questions.map((q, idx) => (
            <div
              key={idx}
              onClick={() => setActiveTab(idx)}
              style={{
                padding: "12px",
                backgroundColor:
                  activeTab === idx
                    ? "rgba(255, 71, 126, 0.2)"
                    : "rgba(255,255,255,0.03)",
                border:
                  activeTab === idx
                    ? "1px solid #ff477e"
                    : "1px solid rgba(255,255,255,0.1)",
                borderRadius: "8px",
                marginBottom: "10px",
                cursor: "pointer",
                transition: "all 0.2s",
              }}
            >
              <div
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  marginBottom: "4px",
                }}
              >
                <span style={{ color: "white", fontWeight: "bold" }}>
                  Soal {idx + 1}
                </span>
                <span style={{ color: "#f0944d", fontSize: "0.8rem" }}>
                  {q.level}
                </span>
              </div>
              <p
                style={{
                  color: "#a0a5b5",
                  fontSize: "0.85rem",
                  margin: 0,
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {q.content || "Kosong..."}
              </p>
            </div>
          ))}
          <button
            onClick={handleAddQuestion}
            disabled={isLoading}
            style={{
              width: "100%",
              padding: "12px",
              backgroundColor: "transparent",
              border: "2px dashed rgba(255,255,255,0.2)",
              color: "white",
              borderRadius: "8px",
              cursor: isLoading ? "not-allowed" : "pointer",
              fontWeight: "bold",
              opacity: isLoading ? 0.5 : 1,
            }}
          >
            + Tambah Soal
          </button>
        </div>
      </div>

      {/* Area Utama Editor Soal (Gaya Quizizz) */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
        {questions.length > 0 && activeQ ? (
          <>
            <div
              style={{
                display: "flex",
                justifyContent: "flex-end",
                marginBottom: "1rem",
                gap: "1rem",
              }}
            >
              <button
                onClick={() => handleDelete(activeTab)}
                disabled={isLoading}
                style={{
                  padding: "10px 20px",
                  backgroundColor: "rgba(239, 68, 68, 0.2)",
                  color: "#ef4444",
                  border: "1px solid #ef4444",
                  borderRadius: "8px",
                  cursor: isLoading ? "not-allowed" : "pointer",
                  fontWeight: "bold",
                  opacity: isLoading ? 0.5 : 1,
                }}
              >
                Hapus Soal
              </button>
              <button
                onClick={handleSaveAll}
                disabled={isLoading}
                style={{
                  padding: "10px 20px",
                  backgroundColor: isLoading ? "#a0a5b5" : "#22c55e",
                  color: "white",
                  border: "none",
                  borderRadius: "8px",
                  cursor: isLoading ? "not-allowed" : "pointer",
                  fontWeight: "bold",
                  boxShadow: isLoading
                    ? "none"
                    : "0 4px 15px rgba(34, 197, 94, 0.3)",
                }}
              >
                {isLoading ? "Menyimpan..." : "Simpan Semua"}
              </button>
            </div>

            <div
              style={{
                backgroundColor: "rgba(255,255,255,0.05)",
                backdropFilter: "blur(10px)",
                border: "1px solid rgba(255,255,255,0.1)",
                borderRadius: "16px",
                padding: "2rem",
                flex: 1,
                display: "flex",
                flexDirection: "column",
                gap: "1.5rem",
              }}
            >
              {/* Toolbar Atas */}
              <div style={{ display: "flex", gap: "1rem" }}>
                <select
                  value={activeQ.level}
                  onChange={(e) => handleUpdate("level", e.target.value)}
                  disabled={isLoading}
                  style={{
                    padding: "10px 16px",
                    borderRadius: "8px",
                    backgroundColor: "rgba(0,0,0,0.3)",
                    color: "white",
                    border: "1px solid rgba(255,255,255,0.2)",
                    outline: "none",
                  }}
                >
                  <option value="Easy">Level: Easy</option>
                  <option value="Medium">Level: Medium</option>
                  <option value="Hard">Level: Hard</option>
                </select>
                <select
                  value={activeQ.timeLimit}
                  onChange={(e) =>
                    handleUpdate("timeLimit", parseInt(e.target.value))
                  }
                  disabled={isLoading}
                  style={{
                    padding: "10px 16px",
                    borderRadius: "8px",
                    backgroundColor: "rgba(0,0,0,0.3)",
                    color: "white",
                    border: "1px solid rgba(255,255,255,0.2)",
                    outline: "none",
                  }}
                >
                  <option value={10}>10 detik</option>
                  <option value={20}>20 detik</option>
                  <option value={30}>30 detik</option>
                  <option value={45}>45 detik</option>
                  <option value={60}>60 detik</option>
                  <option value={120}>120 detik</option>
                </select>
              </div>

              {/* Teks Soal */}
              <div>
                <textarea
                  placeholder="Ketik pertanyaan Anda di sini..."
                  value={activeQ.content}
                  onChange={(e) => handleUpdate("content", e.target.value)}
                  disabled={isLoading}
                  style={{
                    width: "100%",
                    height: "150px",
                    padding: "20px",
                    borderRadius: "12px",
                    backgroundColor: "rgba(0,0,0,0.3)",
                    border: "1px solid rgba(255,255,255,0.2)",
                    color: "white",
                    fontSize: "1.2rem",
                    outline: "none",
                    resize: "none",
                    textAlign: "center",
                  }}
                />
              </div>

              {/* Pilihan Ganda */}
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 1fr",
                  gap: "1rem",
                  flex: 1,
                }}
              >
                {activeQ.options.map((opt, idx) => {
                  const colors = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444"];
                  const isCorrect = activeQ.correct_index === idx;

                  return (
                    <div
                      key={idx}
                      style={{
                        position: "relative",
                        display: "flex",
                        alignItems: "center",
                        backgroundColor: colors[idx],
                        borderRadius: "12px",
                        padding: "4px",
                        opacity: isCorrect ? 1 : 0.8,
                        boxShadow: isCorrect ? `0 0 0 4px white` : "none",
                        transition: "all 0.2s",
                      }}
                    >
                      {/* Checkbox Jawaban Benar */}
                      <div
                        onClick={() =>
                          !isLoading && handleUpdate("correct_index", idx)
                        }
                        style={{
                          width: "40px",
                          height: "100%",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          cursor: isLoading ? "not-allowed" : "pointer",
                          borderRight: "1px solid rgba(255,255,255,0.2)",
                        }}
                        title="Tandai sebagai jawaban benar"
                      >
                        <div
                          style={{
                            width: "24px",
                            height: "24px",
                            borderRadius: "50%",
                            border: "2px solid white",
                            backgroundColor: isCorrect
                              ? "white"
                              : "transparent",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                          }}
                        >
                          {isCorrect && (
                            <span
                              style={{
                                color: colors[idx],
                                fontWeight: "bold",
                                fontSize: "0.9rem",
                              }}
                            >
                              ✓
                            </span>
                          )}
                        </div>
                      </div>

                      {/* Input Jawaban */}
                      <textarea
                        value={opt}
                        onChange={(e) =>
                          handleOptionChange(idx, e.target.value)
                        }
                        disabled={isLoading}
                        placeholder={`Tambahkan opsi jawaban...`}
                        style={{
                          flex: 1,
                          height: "100px",
                          padding: "12px 16px",
                          backgroundColor: "transparent",
                          border: "none",
                          color: "white",
                          fontSize: "1.1rem",
                          outline: "none",
                          resize: "none",
                        }}
                      />
                    </div>
                  );
                })}
              </div>
            </div>
          </>
        ) : (
          <div
            style={{
              flex: 1,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "#a0a5b5",
            }}
          >
            Belum ada soal. Klik + Tambah Soal.
          </div>
        )}
      </div>
    </div>
  );
}

