"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { fetchApi } from "../../../utils/api";
import DashboardHeader from "../../../components/dashboard/DashboardHeader";
import ClassroomCard from "../../../components/admin/ClassroomCard";

export default function ClassroomPage() {
  const [isAdmin, setIsAdmin] = useState(false);
  const [classrooms, setClassrooms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [userRole, setUserRole] = useState("");

  useEffect(() => {
    const fetchClassrooms = async () => {
      try {
        const result = await fetchApi("/api/v1/classrooms/me");
        setClassrooms(Array.isArray(result.data) ? result.data : []);
      } catch (err: any) {
        setError(err.message || "Gagal mengambil data kelas");
      } finally {
        setLoading(false);
      }
    };

    const userRole = localStorage.getItem("userRole");

    if (
      userRole === "admin" ||
      userRole === "SUPER_ADMIN" ||
      userRole === "ADMIN"
    ) {
      setIsAdmin(true);
    }

    if (userRole) setUserRole(userRole);

    fetchClassrooms();
  }, []);

  return (
    <main
      className="mobile-scroll-fix"
      style={{
        minHeight: "100vh",
        backgroundImage: 'url("/bg_kelas.png")',
        backgroundSize: "cover",
        backgroundPosition: "center",
        position: "relative",
        padding: "2rem",
      }}
    >
      {/* Dark overlay to make UI pop */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: "rgba(15, 16, 21, 0.4)",
          zIndex: 0,
        }}
      ></div>

      <DashboardHeader
        isAdmin={isAdmin}
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <div
        className="mobile-dashboard-title"
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "1200px",
          margin: "0 auto",
          paddingTop: "6rem",
        }}
      >
        {/* Title */}
        <div style={{ textAlign: "center", marginBottom: "4rem" }}>
          <h1
            className="animate-fade-in"
            style={{
              fontSize: "2.5rem",
              color: "white",
              textShadow: "0 4px 15px rgba(255, 71, 126, 0.5)",
            }}
          >
            My Classroom
          </h1>
        </div>

        {/* Classroom Selection */}
        <div className="animate-fade-in">
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))",
              gap: "2rem",
            }}
          >
            {Array.isArray(classrooms) && classrooms.length > 0 ? (
              classrooms.map((cls: any) => (
                <ClassroomCard key={cls.id} cls={cls} role={userRole} />
              ))
            ) : (
              <div style={{ 
                color: "white", 
                textAlign: "center", 
                gridColumn: "1 / -1", 
                padding: "3rem 2rem", 
                fontSize: "1.2rem", 
                fontWeight: "500"
              }}>
                Anda belum bergabung dengan classroom manapun.
              </div>
            )}
          </div>
        </div>
      </div>
    </main>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import toast from "react-hot-toast";
import ProfileBadge from "../../components/ProfileBadge";
import { fetchApi } from "../../utils/api";
import DashboardHeader from "../../components/dashboard/DashboardHeader";
import JoinLayout from "../../components/dashboard/ClassroomJoinCard";
import TextInput from "../../components/auth/TextInput";
import { useRouter } from "next/navigation";

export default function ClassroomPage() {
  const [isAdmin, setIsAdmin] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [userRole, setUserRole] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [identifier, setIdentifier] = useState("");
  const router = useRouter();

  const handleJoin = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!identifier.trim()) {
      toast.error("Kode classroom wajib diisi.");
      return;
    }

    setIsSubmitting(true);

    try {
      const result = await fetchApi("/api/v1/classrooms/join", {
        method: "POST",
        body: JSON.stringify({
          code: identifier.trim(),
        }),
      });

      toast.success(result.message || "Berhasil bergabung ke classroom.");

      // Kosongkan input
      setIdentifier("");

      // Jika ingin redirect setelah join
      router.push("/dashboard/classrooms");
    } catch (err: any) {
      let errorMsg = err.message || "Gagal bergabung ke classroom.";
      if (errorMsg.toLowerCase().includes("not found")) {
        errorMsg = "Kode kelas tidak ditemukan";
      }
      toast.error(errorMsg);
      console.log(err);
      console.log(err.response);
      console.log(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  useEffect(() => {
    // Ambil gender dan role pemain dari localStorage (diset saat daftar/login)
    setUserRole(localStorage.getItem("userRole") || "");
    const userRole = localStorage.getItem("userRole");

    if (
      userRole === "admin" ||
      userRole === "SUPER_ADMIN" ||
      userRole === "ADMIN"
    ) {
      setIsAdmin(true);
    }
  }, []);

  return (
    <main
      className="mobile-scroll-fix"
      style={{
        minHeight: "100vh",
        backgroundImage: 'url("/bg_kelas.png")',
        backgroundSize: "cover",
        backgroundPosition: "center",
        position: "relative",
        padding: "2rem",
      }}
    >
      {/* Dark overlay to make UI pop */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: "rgba(15, 16, 21, 0.4)",
          zIndex: 0,
        }}
      ></div>

      <DashboardHeader
        isAdmin={isAdmin}
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
      />

      <div
        className="mobile-dashboard-title"
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "1200px",
          margin: "0 auto",
          paddingTop: "6rem",
        }}
      >
        {/* Title */}
        <div className="desktop-only" style={{ textAlign: "center", marginBottom: "4rem", width: "100%", justifyContent: "center" }}>
          <h1
            className="animate-fade-in"
            style={{
              fontSize: "2.5rem",
              color: "white",
              textShadow: "0 4px 15px rgba(255, 71, 126, 0.5)",
            }}
          >
            Join Classroom
          </h1>
        </div>

        {/* Classroom Join */}
        <JoinLayout title="Masuk" subtitle="Silahkan masuk ke classroom">
          <form
            onSubmit={handleJoin}
            style={{ display: "flex", flexDirection: "column", gap: "1rem" }}
          >
            <TextInput
              label="Kode Classroom"
              type="text"
              value={identifier}
              onChange={(e) => setIdentifier(e.target.value)}
              placeholder="Masukan kode classroom"
              disabled={isSubmitting}
            />

            <button
              type="submit"
              disabled={isSubmitting}
              style={{
                width: "100%",
                padding: "12px",
                backgroundColor: isSubmitting ? "#a0a5b5" : "#ff477e",
                color: "white",
                border: "none",
                borderRadius: "8px",
                fontWeight: "600",
                fontSize: "1rem",
                marginTop: "1rem",
                cursor: isSubmitting ? "not-allowed" : "pointer",
                boxShadow: isSubmitting
                  ? "none"
                  : "0 4px 14px rgba(255, 71, 126, 0.4)",
              }}
            >
              {isSubmitting ? "Memeriksa..." : "Masuk"}
            </button>
          </form>
        </JoinLayout>
      </div>
    </main>
  );
}

"use client";

import { useState, useEffect, use, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { charactersData, mockDialogues } from "../../../data/mockData";

import { mapTopicsToCharacters } from "../../../utils/characterMapper";
import { fetchApi } from "../../../utils/api";
import DialogBox from "../../../components/dialog/DialogBox";
import { Character } from "../../../types";

function DialogContent({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const resolvedParams = use(params);
  const [character, setCharacter] = useState<any>(null);

  const [currentLine, setCurrentLine] = useState(0);
  const [dialogues, setDialogues] = useState<string[]>([]);

  const searchParams = useSearchParams();
  const level = searchParams.get("level") || "easy";
  const count = searchParams.get("count") || "5";

  useEffect(() => {
    const loadDialogData = async () => {
      const userGender = localStorage.getItem("userGender");
      const isFemale = userGender?.toLowerCase() === "female";

      try {
        const res = await fetchApi(`/api/v1/topics/${resolvedParams.id}`);
        const topic = res.data;

        const character = {
          id: topic.id,
          topicId: topic.id,
          topicName: topic.name,
          name: topic.name,
          info: topic.description,

          image: isFemale ? topic.male_normal_img : topic.female_normal_img,

          dialog: isFemale
            ? topic.male_normal_dialog
            : topic.female_normal_dialog,

          datingImage: isFemale
            ? topic.male_dating_img
            : topic.female_dating_img,

          datingDialog: isFemale
            ? topic.male_dating_dialog
            : topic.female_dating_dialog,
        };

        setCharacter(character);

        setDialogues(
          character.dialog
            ? character.dialog.split("|")
            : ["Mari kita mulai kuisnya!"],
        );
      } catch (err) {
        console.error(err);
        router.push("/dashboard");
      }
    };

    loadDialogData();
  }, [resolvedParams.id, router]);

  const handleNext = () => {
    if (currentLine < dialogues.length - 1) {
      setCurrentLine(currentLine + 1);
    } else {
      router.push(`/quiz/${resolvedParams.id}?level=${level}&count=${count}`);
    }
  };

  const handleSkip = () => {
    router.push(`/quiz/${resolvedParams.id}?level=${level}&count=${count}`);
  };

  if (!character || dialogues.length === 0) return null;

  return (
    <main
      className="dialog-main"
      onClick={handleNext}
      style={{
        height: "100vh",
        maxHeight: "100vh",
        backgroundImage: 'url("/bg_dialog.png")',
        backgroundSize: "cover",
        backgroundPosition: "center",
        position: "relative",
        overflow: "hidden",
        cursor: "pointer",
      }}
    >
      {/* Skip Button */}
      <button
        onClick={(e) => {
          e.stopPropagation();
          handleSkip();
        }}
        style={{
          position: "absolute",
          top: "1.5rem",
          right: "1.5rem",
          zIndex: 10,
          padding: "8px 24px",
          backgroundColor: "rgba(255,255,255,0.2)",
          border: "1px solid rgba(255,255,255,0.4)",
          borderRadius: "20px",
          color: "white",
          fontWeight: "bold",
          cursor: "pointer",
          backdropFilter: "blur(5px)",
        }}
      >
        Lewati
      </button>

      {/* Character Image (Zoomed In Half-Body) */}
      <img
        src={character.image}
        alt={character.name}
        className="animate-fade-in dialog-char-img"
        style={{
          position: "absolute",
          top: "5%",
          left: "25%",
          transform: "translateX(-50%)",
          height: "140%",
          objectFit: "contain",
          objectPosition: "top center",
          zIndex: 5,
          pointerEvents: "none",
        }}
      />

      {/* Dialog Box Area */}
      <DialogBox
        characterName={character.name}
        dialogueText={dialogues[currentLine]}
        currentLine={currentLine}
      />
    </main>
  );
}

export default function DialogPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  return (
    <Suspense
      fallback={
        <div
          style={{
            minHeight: "100vh",
            backgroundColor: "#0f1015",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: "white",
          }}
        >
          Memuat Dialog...
        </div>
      }
    >
      <DialogContent params={params} />
    </Suspense>
  );
}

